
INSERT INTO public.opportunities (title, category, description, revenue_estimate, downloads, market_size, growth_percent, competition_score, opportunity_score, growth_velocity, is_hidden_gem, tags) VALUES

-- ── AI Writing & Communication ──
('AI Email Triage & Drafting Tool', 'Productivity', 'Categorizes, prioritizes, and drafts replies for inboxes processing 100+ emails/day. Knowledge workers spend 28% of workday on email; AI inbox management returns 2 hours daily.', '$6k–$40k MRR', '1M+/mo', '$5.5B', 84, 46, 91, 'Explosive', true, ARRAY['productivity','email','AI','writing']),
('AI Slack Message Summarizer', 'Productivity', 'Summarizes unread Slack threads and channels into a 2-minute morning briefing. Average professional loses 72 minutes/day to Slack; summary digest restores deep work time.', '$5k–$30k MRR', '500k+/mo', '$3.5B', 82, 42, 90, 'Explosive', true, ARRAY['productivity','Slack','AI','async']),
('AI Report & Memo Generator', 'Productivity', 'Transforms bullet points and data into polished business reports, memos, and summaries. Executives spend 23% of time writing reports; AI compresses 3 hours to 15 minutes per document.', '$6k–$38k MRR', '300k+/mo', '$4.2B', 80, 44, 89, 'Rising', false, ARRAY['productivity','writing','AI','reports']),
('AI Meeting Summarizer & Action Item Extractor', 'Productivity', 'Auto-generates meeting summaries and assigns action items with deadlines from recorded meetings. $37B wasted annually on unproductive meetings; action item tracking reduces follow-through failures 60%.', '$6k–$40k MRR', '800k+/mo', '$4.8B', 82, 46, 90, 'Explosive', false, ARRAY['productivity','meetings','AI','summaries']),
('AI Proposal & Pitch Deck Generator', 'Productivity', 'Builds client proposals and pitch decks from a brief in 5 minutes with brand-consistent design. Agencies and consultants spend 8 hours per proposal; AI reduces to 30 minutes with higher conversion.', '$8k–$55k MRR', '200k+/mo', '$4.5B', 82, 42, 91, 'Explosive', true, ARRAY['productivity','proposals','AI','sales']),
('Voice-to-Structured-Notes App', 'Productivity', 'Speaks thoughts aloud; AI transcribes and organizes into tagged, searchable structured notes. Physicians, lawyers, and consultants need hands-free capture; existing voice tools output unstructured text.', '$4k–$24k MRR', '400k+/mo', '$3.2B', 80, 40, 90, 'Rising', true, ARRAY['productivity','voice','notes','AI']),

-- ── Project & Task Management ──
('AI Sprint Planning Assistant', 'Productivity', 'Reviews backlog, estimates stories, and suggests sprint compositions based on team velocity. Jira overwhelms solo teams; Linear is clean but not AI-powered; sprint AI is the missing layer.', '$6k–$40k MRR', '150k+/mo', '$4.5B', 80, 42, 90, 'Rising', true, ARRAY['productivity','sprint','AI','project-management']),
('AI OKR Management Platform', 'Productivity', 'Helps teams set measurable OKRs, tracks progress, and surfaces blockers automatically. 70% of companies fail to execute strategy due to poor OKR visibility; AI keeps alignment in real time.', '$8k–$55k MRR', '100k+/mo', '$4.8B', 78, 40, 89, 'Rising', true, ARRAY['productivity','OKR','strategy','AI']),
('Personal Task AI Prioritizer', 'Productivity', 'Scores and reorders your task list by urgency, importance, and energy level each morning. 83% of people feel their to-do list is out of control; AI priority scoring restores clarity.', '$3k–$18k MRR', '2M+/mo', '$3.0B', 78, 52, 86, 'Rising', false, ARRAY['productivity','tasks','AI','prioritization']),
('Team Async Status Update Tool', 'Productivity', 'Daily async standup where AI synthesizes team updates and flags blockers for managers. Remote teams waste 45 min/day on status meetings; async AI standup replaces sync overhead.', '$5k–$30k MRR', '200k+/mo', '$3.5B', 78, 42, 88, 'Rising', true, ARRAY['productivity','async','standup','remote']),
('Cross-App Task Aggregator', 'Productivity', 'Pulls tasks from Jira, GitHub, Notion, and email into one AI-prioritized daily view. Average knowledge worker has tasks in 5+ tools; aggregation with AI priority cuts tool-switching 80%.', '$4k–$24k MRR', '600k+/mo', '$3.8B', 80, 44, 89, 'Rising', true, ARRAY['productivity','tasks','integration','AI']),

