('Energy Management & Peak Hours Tracker', 'Productivity', 'Learns your cognitive peak times from calendar behavior and schedules demanding tasks accordingly. Circadian rhythm alignment improves cognitive output 20%; no app maps personal peak hours automatically.', '$3k–$18k MRR', '1M+/mo', '$2.2B', 76, 42, 86, 'Rising', true, ARRAY['productivity','energy','peak-performance','AI']),
('AI Burnout Early Warning System', 'Productivity', 'Monitors work patterns, meeting load, and after-hours activity to flag burnout risk weeks ahead. $300B annual US productivity loss from burnout; early warning gives 4-6 week intervention window.', '$4k–$24k MRR', '500k+/mo', '$3.5B', 78, 38, 89, 'Rising', true, ARRAY['productivity','burnout','wellbeing','AI']),
('Contextual Do Not Disturb Manager', 'Productivity', 'Intelligently manages notification silence based on calendar, location, and current activity. Average person is interrupted 56 times/day; 80% of interruptions are self-rated as unimportant.', '$2k–$12k MRR', '3M+/mo', '$1.8B', 74, 50, 82, 'Rising', false, ARRAY['productivity','notifications','focus','automation']),

